using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;
using Unity.Netcode;
using Unity.Netcode.Transports.UTP;
using System.Collections.Generic;

public class ArenaBuild
{
    public static string Main()
    {
        var scene = EditorSceneManager.GetActiveScene();
        if (scene.name != "Arena") return "ERROR: Arena scene not active";

        // Grey material
        System.IO.Directory.CreateDirectory("Assets/Materials");
        var greyMat = new Material(Shader.Find("Universal Render Pipeline/Lit"));
        greyMat.color = new Color(0.5f, 0.5f, 0.5f, 1f);
        AssetDatabase.CreateAsset(greyMat, "Assets/Materials/ArenaGrey.mat");
        AssetDatabase.SaveAssets();

        // -- GROUND (20x30, top surface at y=0) --
        var ground = GameObject.CreatePrimitive(PrimitiveType.Cube);
        ground.name = "Ground";
        ground.transform.position = new Vector3(0f, -0.1f, 0f);
        ground.transform.localScale = new Vector3(20f, 0.2f, 30f);
        ground.GetComponent<Renderer>().sharedMaterial = greyMat;
        // Mark as static so NavMesh can be baked on it
        GameObjectUtility.SetStaticEditorFlags(ground, StaticEditorFlags.NavigationStatic);

        // -- WALLS (4 boxes surrounding the arena) --
        var wallParent = new GameObject("Walls");
        float wallH = 2.5f;
        float wallT = 0.5f;

        MakeWall(wallParent, greyMat, "Wall_Left",  new Vector3(-10.25f, wallH * 0.5f, 0f),  new Vector3(wallT, wallH, 31f));
        MakeWall(wallParent, greyMat, "Wall_Right", new Vector3( 10.25f, wallH * 0.5f, 0f),  new Vector3(wallT, wallH, 31f));
        MakeWall(wallParent, greyMat, "Wall_Back",  new Vector3(0f, wallH * 0.5f, -15.25f),  new Vector3(21f, wallH, wallT));
        MakeWall(wallParent, greyMat, "Wall_Front", new Vector3(0f, wallH * 0.5f,  15.25f),  new Vector3(21f, wallH, wallT));

        // -- RANDOM OBSTACLES (8 grey cubes, sitting on ground) --
        var obstParent = new GameObject("Obstacles");
        var rng = new System.Random(42);
        var placed = new List<Rect>();

        float[,] defs = {
            {1.5f, 1.2f, 1.5f}, {2f, 1.8f, 1f}, {1f, 2f, 2f}, {1.8f, 1f, 1.8f},
            {1.2f, 1.5f, 2.5f}, {2.5f, 1.5f, 1.2f}, {1f, 1f, 1f}, {2f, 2f, 1.5f}
        };

        for (int i = 0; i < defs.GetLength(0); i++)
        {
            float bw = defs[i, 0], bh = defs[i, 1], bd = defs[i, 2];
            Vector3 pos = Vector3.zero;
            bool found = false;
            for (int attempt = 0; attempt < 60; attempt++)
            {
                float x = (float)(rng.NextDouble() * 14.0 - 7.0);
                float z = (float)(rng.NextDouble() * 22.0 - 11.0);
                var r = new Rect(x - bw * 0.5f, z - bd * 0.5f, bw, bd);
                bool overlap = false;
                foreach (var p in placed) { if (p.Overlaps(r)) { overlap = true; break; } }
                if (!overlap) { pos = new Vector3(x, bh * 0.5f, z); placed.Add(r); found = true; break; }
            }
            if (!found) continue;

            var ob = GameObject.CreatePrimitive(PrimitiveType.Cube);
            ob.name = "Obstacle_" + i;
            ob.transform.position = pos;
            ob.transform.localScale = new Vector3(bw, bh, bd);
            ob.GetComponent<Renderer>().sharedMaterial = greyMat;
            ob.transform.SetParent(obstParent.transform);
            GameObjectUtility.SetStaticEditorFlags(ob, StaticEditorFlags.NavigationStatic);
        }

        // -- DIRECTIONAL LIGHT --
        var lightGO = new GameObject("Directional Light");
        var light = lightGO.AddComponent<Light>();
        light.type = LightType.Directional;
        light.intensity = 1f;
        lightGO.transform.rotation = Quaternion.Euler(50f, -30f, 0f);

        // -- CAMERA (orthographic top-down, covers full arena) --
        var camGO = new GameObject("Main Camera");
        camGO.tag = "MainCamera";
        var cam = camGO.AddComponent<Camera>();
        cam.orthographic = true;
        cam.orthographicSize = 16f; // 32 units vertical: covers 30 with margin
        cam.clearFlags = CameraClearFlags.SolidColor;
        cam.backgroundColor = new Color(0.1f, 0.1f, 0.15f);
        cam.nearClipPlane = 1f;
        cam.farClipPlane = 60f;
        camGO.transform.position = new Vector3(0f, 35f, 0f);
        camGO.transform.rotation = Quaternion.Euler(90f, 0f, 0f);

        // -- NETWORK MANAGER (root level, with UnityTransport) --
        var nmGO = new GameObject("NetworkManager");
        var nm = nmGO.AddComponent<NetworkManager>();
        var transport = nmGO.AddComponent<UnityTransport>();
        nm.NetworkConfig = new NetworkConfig();
        nm.NetworkConfig.NetworkTransport = transport;

        EditorSceneManager.MarkSceneDirty(scene);
        Debug.Log("[Arena] Build complete: ground, walls, obstacles, camera, NetworkManager.");
        return "success";
    }

    static void MakeWall(GameObject parent, Material mat, string name, Vector3 pos, Vector3 scale)
    {
        var w = GameObject.CreatePrimitive(PrimitiveType.Cube);
        w.name = name;
        w.transform.position = pos;
        w.transform.localScale = scale;
        w.GetComponent<Renderer>().sharedMaterial = mat;
        w.transform.SetParent(parent.transform);
        GameObjectUtility.SetStaticEditorFlags(w, StaticEditorFlags.NavigationStatic);
    }
}
